using System;
using System.Collections.Generic;
using System.Linq;
using Weg.Wdc.Ats.ProductManager.Core.Model;
using Weg.Wdc.SIC.Library;

namespace Weg.Wdc.Ats.F03.ModelImplementation {
    public class Characteristics : ICharacteristics {
        public IProductLabel Label { get; set; }
        public ISAPMaterialInformation SAPMaterialInformation { get; set; }
        public string Family {
            get {
                return SAPMaterialInformation.SAPCharacteristics.Where(c => c.Name.Contains("ZREFERENCIA_PROD") || c.Name.Contains("ZPRODUTO_APLICADO_CELET") || c.Name.Contains("ZPRODUTO_APLIC_1_AEEDRIVE")).First().CharacteristicValue.Description;
            }
        }
        //public string MaterialNumber { get; set; }
        public string FirmwareVersion {
            get {
                string[] splitFwSAP = SAPMaterialInformation.SAPCharacteristics.Where(c => c.Name.Contains("ZSOFTWARE_DRIVE")).Single().CharacteristicValue.Description.Split(new String[] { " ("}, StringSplitOptions.None);

                return splitFwSAP[0].Replace(".", "");

            }
        }
        public string InputNominalVoltage {
            get {
                return SAPMaterialInformation.SAPCharacteristics.Where(c => c.Name.Contains("ZTENSAO_SEM_CABO") || c.Name.Contains("ZTENSAO_ALIMENTACAO") || c.Name.Contains("ZTENSAO_ALIM_ENTRADA_")).Single().CharacteristicValue.Description;
            }
        }
        public bool IsPoweredByDCLink { get { return false; } } // característica ainda não implementada no SAP!
        public string ProductSize {
            get {
                return SAPMaterialInformation.SAPCharacteristics.Where(c => c.Name.Contains("ZMECANICA_DRIVE")).Single().CharacteristicValue.Description;
            }
        } // Check qual a mecânica sendo testada.
        public string NominalCurrent {
            get {
                return string.Concat(SAPMaterialInformation.SAPCharacteristics.Where(c => c.Name.Contains("ZCORRENTE_NOMINAL") || c.Name.Contains(" ZTENSAO_ALIMENTACAO")).Single().CharacteristicValue.Description.Where(Char.IsDigit));
            }
        }
        public string BreakCode {
            get {
                return SAPMaterialInformation.SAPCharacteristics.Where(c => c.Name.Contains("ZFRENAGEM")).Single().CharacteristicValue.Description;
            }
        }
        public string Description {
            get {
                return SAPMaterialInformation.SAPCharacteristics.Where(c => c.Name.Contains("ZCODIGO_INTELIGENTE_")).Single().CharacteristicValue.Value;
            }
        }

        public bool IsTestAuthorized { //verificar INLINE?
            get {
                return SerialNumberItineraryWebServiceWrapper.Instance.IsWorkcenterOperationAllowed(Label.SerialNumber.ToString());
            }
        }

        public bool HasBraking {
            get {
                return BreakCode.Contains("COM"); //COM FRENAGEM REOSTÁTICA OU SEM FRENAGEM REOSTÁTICA.
            }
        }

    }
}

