using System;
using Weg.Wdc.Ats.Core.F03.Model;
using Weg.Wdc.Ats.ReportManager;
using Weg.Wdc.Ats.TestManager.Core.Exception;
using static Weg.Applications.ENS.Integrations.sw_enswebwdc.FunctionalTest;
using static Weg.Applications.ENS.Integrations.sw_enswebwdc.Types;

namespace Weg.Wdc.Ats.TestManager.Core.ModelImplementation {
    public class RheostaticBreakingTest : TestClass {

        public RheostaticBreakingTest() { }
        public RheostaticBreakingTest(ITestPosition TestPosition) : base(TestPosition) {
        }


        protected override void PreProcess() {
            TestLogger.Print($"\n-- TESTE DE FRENAGEM REOSTÁTICA --");
            // verificar se a frenagem está ativa
            TestLogger.Print($"Verificando estado inicial da frenagem: ");
            if (TestPosition.PositionControl.IsBrakingActivated) {
                TestLogger.Print("Falha! Frenagem já ativa antes do comando ser enviado! (Tensão acima do permitido medida no resistor de frenagem)");
                throw new TestExecutionException("Falha! Frenagem já ativa antes do comando ser enviado!", "InitialBreak");
            }
            TestLogger.Print($"Estado inicial OK!");
            TestLogger.Print("Configurando inversor!");
            //Configura Partida pela Serial
            TestPosition.Product.ConfigStartStopSerial();

            //Habilita geral pela serial
            TestPosition.Product.ConfigGeneralHabSerial();

            //Configura rampa de acionamento
            TestPosition.Product.RampTime = 20; // Seta rampa de velocidade para o valor padrão (20 segundos).

            // configurar a frequencia de saída
            TestPosition.Product.MotorSpeedRPM = 1400;

            //garantir que o motor está desconectado
            TestPosition.PositionControl.DisconnectMotor();

        }

        protected override void Validate() {

            //definir o nível de atuação de frenagem
            ajustarNivelDeAtuacaoDaFrenagem();

            // habilitar o inversor
            TestLogger.Print("Habilitando inversor para o teste da frenagem!");
            TestPosition.Product.Run();
            if (TestPosition.Product.OnFault()) {
                TestLogger.Print("Produto indicou falha ao habilitar!");
                EnsRegisterMeasurement(CharacteristicsOptions.Braking, false);
                throw new TestExecutionException("Produto indicou falha ao habilitar!", "BreakHab");
            }

            // medir a tensão entre Br e +UD? 
            TestLogger.Print("Verificando a correta atuação da frenagem: ");
            if (!TestPosition.PositionControl.IsBrakingActivated) {
                TestLogger.Print("Falha! Frenagem não está ativada!");
                EnsRegisterMeasurement(CharacteristicsOptions.Braking, false);
                throw new TestExecutionException("Falha! Frenagem não está ativada!", "NotBreaking");
            }

            TestPosition.Product.Stop();
            EnsRegisterMeasurement(CharacteristicsOptions.Braking, true);

        }

        protected override void PostProcess() {
            TestLogger.Print("Frenagem ativada corretamente!");
            ajustarNivelDeAtuacaoDaFrenagemParaPadrao();       
            TestLogger.Print("Teste aprovado!");
        }

        private  void ajustarNivelDeAtuacaoDaFrenagem() {

            switch (TestPosition.Product.MainPowerSupplyCode) {
                case ProductManager.Core.Types.MainPowerSupplyType.Voltage_220V:
                    TestLogger.Print("Configuração para frenagem T2 selecionada.");
                    TestPosition.Product.SetBreakingLevel(700);
                    break;
                case ProductManager.Core.Types.MainPowerSupplyType.Voltage_440V:
                    TestLogger.Print("Configuração para frenagem T4 selecionada.");
                    TestPosition.Product.SetBreakingLevel(750);
                    break;
                case ProductManager.Core.Types.MainPowerSupplyType.Voltage_575V:
                    TestLogger.Print("Configuração para frenagem T5 selecionada.");
                    TestPosition.Product.SetBreakingLevel(650);
                    break;
                case ProductManager.Core.Types.MainPowerSupplyType.Voltage_690V:
                    TestLogger.Print("Configuração para frenagem T6 selecionada.");
                    TestPosition.Product.SetBreakingLevel(650);
                    break;
                case ProductManager.Core.Types.MainPowerSupplyType.Voltage_NOTFOUND:
                    break;
                default:
                    break;
            }

        }

        private void ajustarNivelDeAtuacaoDaFrenagemParaPadrao() {
            TestPosition.Product.SetBreakingLevel(950);
        }

        private void EnsRegisterMeasurement(CharacteristicsOptions MeasuringPoint, bool TestPassed) {
            TestData.EnsMeasurePoints.Add(new ENSMeasurePoint() {
                measuringPoint = MeasuringPoint,
                testResult = TestPassed ? TestResultType.Approved : TestResultType.Failed
            });
        }
    }
}

