using System;
using System.Collections.Generic;
using System.Linq;
using Weg.Wdc.Ats.ProductManager.Core.Model;
using Weg.Wdc.Ats.Core.Model;
using System.IO.Ports;
using log4net;
using NModbus;
using Weg.Wdc.Ats.ProductManager.Core.Types;
using System.Threading;
using NModbus.Serial;
using System.Diagnostics;

namespace Weg.Wdc.Ats.ProductManager.Core.ModelImplementation {
    public class Product : IProduct {

        private static readonly ILog log = LogManager.GetLogger(System.Reflection.MethodBase.GetCurrentMethod().DeclaringType);
        private readonly byte SLAVE_ADDRESS = 1;


        /* public Product(ISAPMaterialInformation materialInfo) {
             this.MaterialInfo = materialInfo;
         }*/

        //public ISAPMaterialInformation MaterialInfo { get; set; }

        //[SuppressMessage("Microsoft.Usage", "CA1801")]
        //[XmlArray("TestRoutineList")]
        //[XmlArrayItem("TestRoutine")]
        //public IList<ITestRecipe> TestRecipeList { get; set; }


        public string CommunicationPortName { get; set; }



        private IModbusMaster modbusMaster;
        public IModbusMaster ModbusInterface {
            get {
                if (modbusMaster == null) {
                    StartCommunication();
                }
                return modbusMaster;
            }
            set {
                modbusMaster = value;
            }
        }

        public void StartCommunication() {

                modbusMaster = new ModbusFactory().CreateRtuMaster(new SerialPortAdapter(getCommPort()));
                modbusMaster.Transport.Retries = 3;



        }

        SerialPort serialPort;

        protected virtual SerialPort getCommPort() {
            if (serialPort == null) {
                Debug.Write("serial port:" + serialPort);
                serialPort = new SerialPort(CommunicationPortName) {
                    BaudRate = 19200,
                    DataBits = 8,
                    StopBits = StopBits.One,
                    Parity = Parity.Even,
                    ReadTimeout = 100,
                };

            }
            if (!serialPort.IsOpen) {
                serialPort.Open();
            }
            return serialPort;
        }

        public void StopCommunication() {
            getCommPort().Close();
            modbusMaster = null;
            serialPort = null;
        }

        public void CloseCommPort() {
            StopCommunication();

        }

        public void SetSpeedReference(int speedReference) {
            ModbusInterface.WriteSingleRegister(1, 121, (ushort)speedReference);
        }

        public bool Enabled { get; }

        public bool STOActivated {
            get { return false; }
        }

        public bool Running { get; }

        public bool IsCommunicationEstablished() {

            //Lê a tensão de 24V IO, se for maior que 0, estabeleceu comunicação com o produto. 
            try {
                return (ModbusInterface.ReadHoldingRegisters(1, 1004, 1)[0] > 0);
            } catch (TimeoutException) {
                return false;
            }

        }

        public bool IsSlot1HardwareIdCorrect { get; }
        public bool IsSlot2HardwareIdCorrect { get; }
        public bool IsSlot3HardwareIdCorrect { get; }
        public bool IsMemoryHardwareIdCorrect { get; }
        public bool IsPowerHardwareIdCorrect { get; }

        public int Slot1HardwareId { get; }
        public int Slot2HardwareId { get; }
        public int Slot3HardwareId { get; }
        public int MemoryHardwareId { get; }
        public int PowerHardwareId { get; }
        public int PowerHardwareIdExpected { get; }
        public int HeatSinkFanSpeed { get; }
        public int DCLinkVoltage { get; }

        public ICharacteristics Characteristics { get; set; }

        public MainPowerSupplyType MainPowerSupplyCode {
            get {
                if (ContainsAny(Characteristics.InputNominalVoltage, new List<string> { "200", "220", "240" })) {
                    return MainPowerSupplyType.Voltage_220V;
                }
                if (ContainsAny(Characteristics.InputNominalVoltage, new List<string> { "380", "440", "480" })) {
                    return MainPowerSupplyType.Voltage_440V;
                }
                if (ContainsAny(Characteristics.InputNominalVoltage, new List<string> { "500", "600" })) {
                    return MainPowerSupplyType.Voltage_575V;
                }
                if (ContainsAny(Characteristics.InputNominalVoltage, new List<string> { "690" })) {
                    return MainPowerSupplyType.Voltage_690V;
                }

                return MainPowerSupplyType.Voltage_NOTFOUND;
            }

        }

        private bool ContainsAny(string input, List<string> values) {
            return values.Any(value => input.Contains(value));
        }

        public double RampTime {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 100, 1)[0] / 10d;
            }

            set {
                ModbusInterface.WriteSingleRegister(1, 100, (ushort)(value * 10)); // "value" é o valor que está entrando na propertie pelo metodo set. 
            }
        }

        public double RampDownTime {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 101, 1)[0] / 10d;
            }

            set {
                ModbusInterface.WriteSingleRegister(1, 101, (ushort)(value * 10)); // "value" é o valor que está entrando na propertie pelo metodo set. 
            }
        }
        public int MotorSpeedRPM {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 121, 1)[0];
            }
            set {
                ModbusInterface.WriteSingleRegister(1, 121, (ushort)value);
            }
        }

        public int EstimatedMotorSpeed {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 39, 1)[0];
            }

        }

        public void SetDigitalOutputState(int digitalOutputNumber, bool active) {

            switch (digitalOutputNumber) {
                case 1:
                    ModbusInterface.WriteSingleRegister(1, 7155, (ushort)(active ? 1 : 0));

                    break;
                case 2:
                    ModbusInterface.WriteSingleRegister(1, 7156, (ushort)(active ? 1 : 0));
                    break;
                default:
                    break;
            }
        }

        public void ResetToDefaultFactory() {
            ModbusInterface.WriteSingleRegister(1, 204, 1);
        }

        public void ConfigureAccordingList(IList<IParameterConfiguration> parameterConfigrationList) {
            foreach (var paramItem in parameterConfigrationList) {
                try {
                    ModbusInterface.WriteSingleRegister(SLAVE_ADDRESS, (ushort)paramItem.Parameter, (ushort)paramItem.Value);
                } catch (Exception ex) {
                    log.Error(ex);
                    paramItem.Success = false;
                }
                paramItem.Success = true;
            }
        }

        public double PhaseUIgbtTemperature {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 2020, 1)[0] / 10;
            }
        }

        public double PhaseVIgbtTemperature {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 2021, 1)[0] / 10;
            }
        }

        public double PhaseWIgbtTemperature {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 2022, 1)[0] / 10;
            }
        }

        public double InternalAirTemperature {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 2029, 1)[0] / 10;
            }
        }

        public bool OnFault() {
            return ReadStatusCode() == 3;
        }

        public int ReadDIStatus() {
            return ModbusInterface.ReadHoldingRegisters(1, 7016, 1)[0];
        }

        public bool IsRDY() {
            return (ReadStatusCode() == 0);
        }

        public bool OnSTO() {
            return (ReadStatusCode() == 5);
        }

        public void SetAoValue(int AnalogOutputID, int value) {

            ushort aoConfigRegister;

            switch (AnalogOutputID) {
                case 1:
                    aoConfigRegister = 7035;
                    break;
                case 2:
                    aoConfigRegister = 7036;
                    break;

                default:
                    return;
            }
            ModbusInterface.WriteSingleRegister(1, aoConfigRegister, (ushort)(value * 1000));


        }

        public long FwVersionFound() {
            ushort[] registerValues = ModbusInterface.ReadHoldingRegisters(1, 22, 2);

            return (registerValues[1] * 0xFFFF) + registerValues[0];
        }

        public int CurrentFaultCode() {
            return ModbusInterface.ReadHoldingRegisters(1, 60, 1)[0];
        }

        public void BackUpToMicroSD() {
            ModbusInterface.WriteSingleRegister(1, 204, 10);
        }

        public int ReadBpCode() {
            return ModbusInterface.ReadHoldingRegisters(1, 7000, 1)[0];
        }

        public int ReadAccCode() {
            return ModbusInterface.ReadHoldingRegisters(1, 7310, 1)[0];
        }

        public bool OnNominalSpeed() {
            return Helper.isBitSet(ReadStateWord2(), 8);
        }

        double IProduct.OutputCurrent() {
            return ModbusInterface.ReadHoldingRegisters(1, 3, 1)[0]/10d;
        }

        public bool OnStop() {
            return ReadStatusCode() == 7;
        }

        public void BackUpFromMicroSD() {
            ModbusInterface.WriteSingleRegister(1, 204, 9);
        }

        public void Run() {
            ModbusInterface.WriteSingleRegister(1, 682, 67); // Hab Geral, Gira/Para e Desativa a parada rápida.
        }

        public void Stop() {
            ModbusInterface.WriteSingleRegister(1, 682, 0);
        }

        public void RampDown() {
            ModbusInterface.WriteSingleRegister(1, 682, 66);
        }

        public void Configure(IRegister register) {
            ModbusInterface.WriteSingleRegister(1, (ushort)register.Number, (ushort)register.Value);
        }

        public void Configure(IList<IRegister> registers) {
            foreach (var register in registers) {
                Configure(register);
            }
        }


        public bool isSpeedingUp {
            get {
                return Helper.isBitSet(ReadStateWord2(), 6);
            }
        }
        public bool isSlowingDown {
            get {

                return Helper.isBitSet(ReadStateWord2(), 5);
            }
        }

        public string DriveState {
            get {

                switch (ReadStatusCode()) {
                    case 1:
                        return "RUN";

                    case 2:
                        return "SUB";

                    case 3:
                        return "FAULT";

                    case 4:
                        return "CONFIG";

                    case 5:
                        return "STO";

                    case 6:
                        return "POff";

                    case 7:
                        return "Desab";

                    case 8:
                        return "SS1";

                    case 9:
                        return "AAjuste";

                    default:
                        return "";
                }
            }
        }

        public int ReadStatusCode() {
            return ModbusInterface.ReadHoldingRegisters(1, 6, 1)[0];
        }

        public double ReadDCLinkVoltage() {
            return ModbusInterface.ReadHoldingRegisters(1, 4, 1)[0];
        }

        public int ReadMicroSdFlag() {
            return ModbusInterface.ReadHoldingRegisters(1, 691, 1)[0];
        }

        public int ReadEthernetFlag() {
            return ModbusInterface.ReadHoldingRegisters(1, 890, 1)[0];
        }

        public double ReadAI1Value() {
            return ModbusInterface.ReadHoldingRegisters(1, 7017, 1)[0] / 1000d;
        }

        public double ReadAI2Value() {
            return ModbusInterface.ReadHoldingRegisters(1, 7018, 1)[0] / 1000d;
        }

        public void ConfigureInternalFan(int config) {
            ModbusInterface.WriteSingleRegister(1, 2001, (ushort)config);
        }

        public void ConfigurePowerFan(int speedPercent) {
            ModbusInterface.WriteSingleRegister(1, 2007, (ushort)speedPercent);
        }

        public int ReadIntFan1() {
            return ModbusInterface.ReadHoldingRegisters(1, 2018, 1)[0];
        }

        public int ReadIntFan2() {
            return ModbusInterface.ReadHoldingRegisters(1, 2019, 1)[0];
        }

        public int ReadPowFan1() {
            return ModbusInterface.ReadHoldingRegisters(1, 2014, 1)[0];
        }

        public int ReadPowFan2() {
            return ModbusInterface.ReadHoldingRegisters(1, 2015, 1)[0];
        }

        public int ReadPowFan3() {
            return ModbusInterface.ReadHoldingRegisters(1, 2016, 1)[0];
        }

        public void ConfigStartStopSerial() {
            ModbusInterface.WriteSingleRegister(1, 224, 1);
        }

        public void ConfigGeneralHabSerial() {
            ModbusInterface.WriteSingleRegister(1, 240, 2);
        }

        public void ResetFault() {

            ModbusInterface.WriteSingleRegister(1, 682, 128);
            ModbusInterface.WriteSingleRegister(1, 682, 0);

            Thread.Sleep(2000);
        }

        public int ReadStateWord2() {
            return ModbusInterface.ReadHoldingRegisters(1, 690, 1)[0];
        }

        public void SetBreakingLevel(int actuationLevel) {
            ModbusInterface.WriteSingleRegister(1, 153, (ushort)actuationLevel);
        }

        public int ReadAlarmCode() {
            return ModbusInterface.ReadHoldingRegisters(1, 50, 1)[0];
        }

        public void ConfigureRTC(int reg195, int reg194) {
            ushort[] rtcVector = { (ushort)reg194, (ushort)reg195 };
            ModbusInterface.WriteMultipleRegisters(1, 194, rtcVector);

        }

        public double ReadActualTime() {

            ushort[] ActualTimeReg1008 = ModbusInterface.ReadHoldingRegisters(1, 1008, 2);

            string read1009Hex = ActualTimeReg1008[1].ToString("X4");
            string read1008Hex = ActualTimeReg1008[0].ToString("X4");

            string realTimeHex = string.Concat(read1009Hex, read1008Hex);

            double decimalValue = Convert.ToInt32(realTimeHex, 16);

            return decimalValue;
        }

        public void LoadTestParameters() {

            ModbusInterface.WriteSingleRegister(1, 195, 7); // C4.2.1.2 Config. Comandos Loc Gira/PARA = 7 (DI Gira/Para)
            ModbusInterface.WriteSingleRegister(1, 121, 1650); // C4.3.1.3.1 Ref. Velocidade Via HMI, AIs. = 1650
            ModbusInterface.WriteSingleRegister(1, 348, 3); // C7.4.1 Prot. de Sobrecarga do Motor = 3 (Alarme)
            ModbusInterface.WriteSingleRegister(1, 6004, 1); // Config. DIs p/ Comandos Gira/Para = 1 (DI1)
            ModbusInterface.WriteSingleRegister(1, 136, 0); //C3.2.1.1 Boost Torque Manual. 

        }

        public void ConfigAO(int aoId, int aoConfigCode) {

            int aoConfigRegister = 0;
            switch (aoId) {
                case 1:
                    aoConfigRegister = 7187;
                    break;
                case 2:
                    aoConfigRegister = 7188;
                    break;

                default:
                    return;
            }
            ModbusInterface.WriteSingleRegister(1, (ushort)aoConfigRegister, (ushort)aoConfigCode);
        }

        public bool HasFanSpeedControl {
            get {
                return !(Characteristics.Description.Contains("G0430") || Characteristics.Description.Contains("G0480") || Characteristics.Description.Contains("CFW900E"));
            }
        }

        public int BackupMode {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 204, 1)[0];
            }
        }

        public bool isRunning {
            get {
                return Helper.isBitSet(ReadStateWord1(), 8);
            }
        }

        public double IOPowerSupply_24V {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 1004, 1)[0] / 100d;
            }
        }

        public double ControlPowerSupply_3V3 {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 1005, 1)[0] / 100d;
            }
        }

        public double ControlPowerSupply_24V {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 1006, 1)[0] / 100d;
            }
        }

        public double IOPowerSupply_3V3 {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 1007, 1)[0] / 100d;
            }
        }

        public double AUIPowerSupply_5V {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 1002, 1)[0] / 100d;
            }
        }

        public double BatteryPowerSupply {
            get {
                return ModbusInterface.ReadHoldingRegisters(1, 1003, 1)[0] / 100d;
            }
        }

        private int ReadStateWord1() {
            return ModbusInterface.ReadHoldingRegisters(1, 680, 1)[0];
        }

        public bool isPOff() {
            return (ReadStatusCode() == 6);
        }

        public void ConfigurePowerFanState(int fanState) {
            ModbusInterface.WriteSingleRegister(1, 2000, (ushort) fanState);
        }

        public void SuperFactoryReset() {

        }
    }
}

