using System;
using IniParser;
using IniParser.Model;
using Weg.Wdc.Ats.Core.F03.Model;
using Weg.Wdc.Ats.TestManager.Core.ModelImplementation;
using Weg.Wdc.Ats.TestManager.Core.Exception;
using Weg.Wdc.Stf.TSAL;
using System.Diagnostics;

namespace Weg.Wdc.Ats.TestManager.Core.CFW900.ModelImplementation
{
    public class ModelDownload : TestClass
    {
        public ModelDownload() {
        }

        public ModelDownload( ITestPosition TestPosition ) : base(TestPosition)
        {
        }

        protected override void Validate() {
            TestLogger.Print($"-- GRAVAÇÃO DO MODELO --");
            TestLogger.Print("Verificando Comunicação");
            Stopwatch s = new Stopwatch(); //Instancia da classe Stopwatch para marcar o tempo. 
            s.Start(); //inicia a contagem de tempo do Stopwatch

            bool CommStatus = false;
            int ts = 0;
            // Verificação da comunicação inicial. 
            do {
                ts = s.Elapsed.Seconds;
                try {
                    CommStatus = TestPosition.Product.IsCommunicationEstablished();
                } catch (TimeoutException) {

                }

                if (ts > 60) {
                    s.Stop();
                    s.Reset();
                    TestPosition.PositionControl.TurnOffExternalControlPowerSupply();
                    throw new TestExecutionException("Timeout na comunicação ModelDownload", "ComunicationTimeOut");
                }
            }
            while (!CommStatus);

            s.Stop();
            s.Reset();
            TestLogger.Print($"iniciando gravação");

            ProductModelFileTransfer ModelFileTransferManager = new ProductModelFileTransfer();

            string materialNumber = TestPosition.Product.Characteristics.Label.Material.ToString();

            TestPosition.Product.CloseCommPort();

            TestLogger.Print($"Fechando Porta Comm");

            if (!ModelFileTransferManager.executeDefaultModelFileDownloadAndTransfer(materialNumber, portaComm())) {

                throw new TestExecutionException("Falha na gravação do modelo!", "ModelTransfer");
            } else {
                TestLogger.Print($"Gravação do modelo concluída!");

            }

            TestLogger.Print($"Gravação OK!");

            TestLogger.Print($"Abrindo porta Comm");
            try {

                TestPosition.Product.StartCommunication();

            } catch (System.Exception e) {

                TestLogger.Print(e.Message + e.StackTrace);
                TestLogger.Print("\n");
            }




        }

        private string portaComm() //Retornar um String da porta COM.
        {
            var IniFileParser = new FileIniDataParser();
            string filepath = @".\files\STF.ini";


            try
            {
                IniData data = IniFileParser.ReadFile(filepath);

                string portaCommnumber = data["PRODUCT_COMM_PORT"]["Comm"];

                return portaCommnumber;

            }
            catch (IniParser.Exceptions.ParsingException ex)
            {
                Console.WriteLine("INI file parsing error: " + ex.Message);
                throw;

            }

        }

    }
}

