using log4net;
using System;
using System.Threading;
using System.Threading.Tasks;
using Weg.Wdc.Ats.Core.F03.Model;
using Weg.Wdc.Ats.TestManager.Core.Common;
using Weg.Wdc.Ats.TestManager.Core.Exception;

namespace Weg.Wdc.Ats.TestManager.Core.ModelImplementation {
    public class DefaultFactoryConfiguration : TestClass {
        public readonly string DEFAULT_ERROR_CODE = "Padrao_fabrica";

        private static readonly ILog log = LogManager.GetLogger(System.Reflection.MethodBase.GetCurrentMethod().DeclaringType);
        private readonly int NEW_RAMP_TIME = 500;
        private int timeout = 30;
        private readonly int FACTORY_DEFAULT_60HZ_MODE = 1;

        public DefaultFactoryConfiguration(ITestPosition TestPosition) : base(TestPosition) {

        }
        public DefaultFactoryConfiguration(ITestPosition TestPosition, int timeout) : base(TestPosition) {
            this.timeout = timeout;
        }
        public DefaultFactoryConfiguration() {
        }

        protected void PreValidation() {
            TestLogger.Print("\n- Carregando padrão de fábrica.");
            if (!TestPosition.Product.IsCommunicationEstablished()) {
                throw new TestExecutionException("Comunicação com produto não estabelicida", DEFAULT_ERROR_CODE);
            }
        }

        protected override void Validate() {

            waitForNotPOff();

            TestPosition.Product.RampTime = NEW_RAMP_TIME;
            Thread.Sleep(5000);
            TestPosition.Product.ResetToDefaultFactory();

            waitForReset();

            if (TestPosition.Product.OnFault()) {
                TestLogger.Print("- Produto em falha após padrão de fábrica.");
                TestLogger.Print($"- Código da falha: { TestPosition.Product.CurrentFaultCode()}");
                throw new TestExecutionException("Produto em falha após padrão de fábrica", DEFAULT_ERROR_CODE);
            }

            if (TestPosition.Product.RampTime == NEW_RAMP_TIME) {
                TestLogger.Print("- Rampa de aceleração não retornou ao padrão d fábrica.");
                TestLogger.Print($"- Rampa aceleração: { TestPosition.Product.RampTime / 10}s");
                throw new TestExecutionException("Parâmetro não retornou ao padrão de fábrica", DEFAULT_ERROR_CODE);
            }

            TestLogger.Print("Padrão de fábrica carregado com sucesso.");

        }
        private void waitForNotPOff() {
            var task = Task.Run(() => {
                TestLogger.Print("Aguardando inicialização cartão Potência");
                while (TestPosition.Product.isPOff()) {
                    Thread.Sleep(1000);
                }
                TestLogger.Print("Inicialização finalizada!");
            });
            if (!task.Wait(TimeSpan.FromSeconds(20))) {
                TestLogger.Print("FALHA! Comunicação não restabelecida!");
                throw new TestExecutionException("Comunicação não restabelecida", DEFAULT_ERROR_CODE);
            }
        }

        private void waitForReset() {
            var task = Task.Run(() => {
                TestLogger.Print("Aguardando fim do padrão de fábrica...");
                while (TestPosition.Product.BackupMode == FACTORY_DEFAULT_60HZ_MODE) {
                    Thread.Sleep(1000);
                }
                TestLogger.Print("Padrão de fábrica executado!");

                TestLogger.Print("Aguardando Estabilização da comunicação.");
                while (!TestPosition.Product.IsRDY()) {
                    Thread.Sleep(1000);
                }
                TestLogger.Print("comunicação estabelecida.");

            });
            if (!task.Wait(TimeSpan.FromSeconds(20))) {
                TestLogger.Print("FALHA! Comunicação não restabelecida após reset!");

                if (TestPosition.Product.OnFault()) {
                    TestLogger.Print("- Produto em falha após padrão de fábrica.");
                    TestLogger.Print($"- Código da falha: { TestPosition.Product.CurrentFaultCode()}");
                }

                throw new TestExecutionException("Comunicação não restabelecida após reset", DEFAULT_ERROR_CODE);
            }
        }
    }
}

