            string FwSap = TestPosition.Product.Characteristics.FirmwareVersion; //property de get para a versão de firmware. 

            if (String.IsNullOrEmpty(FwSap))// verificando se a pesquisa encontrou algum resultado.
            {
                throw new TestExecutionException("Versão de firmware não encontrada no SAP!", "VersaoFwNotInSAP");
            }
            TestLogger.Print(FwSap);
            long FwVersionSAP = long.Parse(FwSap);

            //Ler a versão de firmware do parâmetro do produto
            long FwVersionFound = TestPosition.Product.FwVersionFound(); //Método() de leitura do parâmetro de versão de firmware.

            TestLogger.Print($"Versão esperada: {FwVersionSAP} \n Versão Lida: {FwVersionFound}");

            //Comparar as versões de firmware
            bool isCorrectVersion = (FwVersionFound == FwVersionSAP);
            if (!isCorrectVersion)
            {
                EnsRegisterMeasurement(CharacteristicsOptions.FirmwareVersion, isCorrectVersion);
                throw new TestExecutionException("Versão de Firmware incorreta!", "VersaoFwIncorreta");
            }

            EnsRegisterMeasurement(CharacteristicsOptions.FirmwareVersion, isCorrectVersion);
            TestLogger.Print($"Versão de Firmware Aprovada!");

        }

        private void EnsRegisterMeasurement(CharacteristicsOptions MeasuringPoint, bool TestPassed) {
            TestData.EnsMeasurePoints.Add(new ENSMeasurePoint() {
                measuringPoint = MeasuringPoint,
                testResult = TestPassed ? TestResultType.Approved : TestResultType.Failed
            });
        }
    }
}

