using System;
using Weg.Wdc.Ats.Core.Common;

namespace Weg.Wdc.Ats.ProductManager.Data.SAP {
    public class MaterialRepository : IMaterialRepository {

        public ISAPMaterialInformation FindByMaterial(long material) {
            ValidateInput(material, "Value can't be zero.");
            SAPMaterialService service = new SAPMaterialService();
            return Generate(service.Find(new DTP_MATERIALMaterialSearchByMaterialMaterial() {
                MaterialNumber = material.ToString(CultureInfo.CurrentCulture)
            }).First());
        }

        public ISAPMaterialInformation FindByProductionOrder(long po) {
            SAPMaterialSerialNumberService service = new SAPMaterialSerialNumberService();
            string materialString = service.FindByProductionOrder(po).First().Material;
            return FindByMaterial(long.Parse(materialString));
        }

        public ISAPMaterialInformation FindBySerialNumber(long serial) {
            SAPMaterialSerialNumberService service = new SAPMaterialSerialNumberService();
            string materialString = service.FindBySerialNumber(serial).First().Material;
            return FindByMaterial(long.Parse(materialString));
        }

        private ISAPMaterialInformation Generate(DTP_MATERIAL_RMaterial sapMaterial) {
            ISAPMaterialInformation material = new SAPMaterialInformation() {
                SAPCharacteristics = SAPMaterialService.ExtractAllCharacteristicsFromMaterial(sapMaterial),
                SAPDocuments = SAPMaterialService.ExtractDocumentsFromMaterial(sapMaterial),
            };

            return material;
        }

        private void ValidateInput(long input, string exceptionMsg) {
            if (input == 0) {
                throw new WdcException(exceptionMsg);
            }
        }
    }
}

