using Weg.Wdc.Ats.ProductManager.Core.Model;
using Weg.Wdc.Ats.ProductManager.Core.ModelImplementation;
using Weg.Wdc.Ats.ProductManager.Data.SAP.Service.Validator;
using System;
using System.Collections.Generic;
using System.Linq;
using Weg.Soa.ServiceClient.Material;
using Weg.Wdc.Ats.ProductManager.Data.SAP.Properties;

namespace Weg.Wdc.Ats.ProductManager.Data.SAP.Service {
    public class SAPMaterialService : SAPServiceAbstract<ITF_O_S_MATERIAL, ITF_O_S_MATERIALRequest, ITF_O_S_MATERIALResponse> {

        const string MATERIALS_CLASS_NUMBER = "001";

        public SAPMaterialService() {
            ServiceValidator = new SAPMaterialServiceValidator();
        }

        internal ITF_O_S_MATERIALRequest CreateRequest() {
            return new ITF_O_S_MATERIALRequest() {
                MTP_MATERIAL = new DTP_MATERIAL() {
                    Material = new DTP_MATERIALMaterial() {
                        language = Settings.Default.LANGUAGE,
                        Plant = Settings.Default.PLANT,
                        ValidFrom = DateTime.Now,
                        ReturnClassification = true,
                        ReturnVariantEvaluation = true,
                        LoadValueDesc = true,
                        SearchBy = new DTP_MATERIALMaterialSearchBy() {
                            Material = new DTP_MATERIALMaterialSearchByMaterial() {
                                MaterialList = new List<DTP_MATERIALMaterialSearchByMaterialMaterial>().ToArray()
                            }
                        }
                    }
                }
            };
        }

        public IEnumerable<DTP_MATERIAL_RMaterial> Find(DTP_MATERIALMaterialSearchByMaterialMaterial[] materialList) {
            ITF_O_S_MATERIALRequest request = CreateRequest();
            request.MTP_MATERIAL.Material.SearchBy.Material.MaterialList = materialList;
            return ExecuteService(request).MTP_MATERIAL_R.MaterialList.ToList();
        }

        private ITF_O_S_MATERIALResponse ExecuteService(ITF_O_S_MATERIALRequest request) {
            ValidateRequest(request);
            ITF_O_S_MATERIALResponse response = Service.ITF_O_S_MATERIAL(request);
            ValidateResponse(response);
            return response;
        }

        public IEnumerable<DTP_MATERIAL_RMaterial> Find(DTP_MATERIALMaterialSearchByMaterialMaterial material) {
            return Find(new DTP_MATERIALMaterialSearchByMaterialMaterial[] { material });
        }

        public static IList<ISAPCharacteristic> ExtractAllCharacteristicsFromMaterial(DTP_MATERIAL_RMaterial sapMaterial) {
            List<ISAPCharacteristic> characteristicList = new List<ISAPCharacteristic>();
            characteristicList.AddRange(ExtractCharacteristicsFromClassificationClass(sapMaterial));
            characteristicList.AddRange(ExtractCharacteristicsFromVariantConfiguration(sapMaterial));
            return characteristicList;
        }

        private static IList<ISAPCharacteristic> ExtractCharacteristicsFromVariantConfiguration(DTP_MATERIAL_RMaterial sapMaterial) {
            IList<ISAPCharacteristic> variantCharacteristicList = new List<ISAPCharacteristic>();
            if (sapMaterial.ClientSpecificConfiguration !=null && sapMaterial.ClientSpecificConfiguration.IsVariant) {
                variantCharacteristicList = GetAllVariantCharacteristics(sapMaterial);
            }
            return variantCharacteristicList;
        }

        private static IList<ISAPCharacteristic> GetAllVariantCharacteristics(DTP_MATERIAL_RMaterial sapMaterial) {
            IList<ISAPCharacteristic> variantCharacteristicList = new List<ISAPCharacteristic>();
            foreach (DTP_MATERIAL_RMaterialClientSpecificConfigurationVariantConfigurationCharacteristic item in sapMaterial.ClientSpecificConfiguration.VariantConfiguration.CharacteristicList) {
                variantCharacteristicList.Add(new SAPCharacteristic() {
                    Name = item.Name,
                    CharacteristicValue = new SAPCharacteristicValue() {
                        Description = item.ValueList.Description,
                        Value = item.ValueList.Value
                    }
                });
            }
            return variantCharacteristicList;
        }

        private static IList<ISAPCharacteristic> ExtractCharacteristicsFromClassificationClass(DTP_MATERIAL_RMaterial sapMaterial) {
            DTP_MATERIAL_RMaterialClassificationClassType classType = GetProductClassificationClassType(sapMaterial);
            List<ISAPCharacteristic> characteristicList = new List<ISAPCharacteristic>();
            foreach(DTP_MATERIAL_RMaterialClassificationClassTypeClass classificationClass in classType.ClassList) {
                characteristicList.AddRange(ExtractCharacteristListFromClass(classificationClass));
            }
            return characteristicList;
        }

        private static IList<ISAPCharacteristic> ExtractCharacteristListFromClass(DTP_MATERIAL_RMaterialClassificationClassTypeClass classType) {
            IList<ISAPCharacteristic> characteristicList = new List<ISAPCharacteristic>();
            foreach (var charact in classType.CharacteristicList) {
                characteristicList.Add(createCharacteristic(charact));
            }
            return characteristicList;
        }

        private static ISAPCharacteristic createCharacteristic(DTP_MATERIAL_RMaterialClassificationClassTypeClassCharacteristic charact) {
            return new SAPCharacteristic() {
                Name = getCharactName(charact),
                CharacteristicValue = (charact == null ? new SAPCharacteristicValue() : getCharacteristicValues(charact))
            };
        }

        private static ISAPCharacteristicValue getCharacteristicValues(DTP_MATERIAL_RMaterialClassificationClassTypeClassCharacteristic charact) {
            return new SAPCharacteristicValue() {
                Description = charact.ComplexValueList.ToList().First().Description,
                Value = charact.ComplexValueList.ToList().First().Value
            };
        }

        private static string getCharactName(DTP_MATERIAL_RMaterialClassificationClassTypeClassCharacteristic charact) {
            return charact.Name;
        }

        private static DTP_MATERIAL_RMaterialClassificationClassType GetProductClassificationClassType(DTP_MATERIAL_RMaterial sapMaterial) {
            return sapMaterial.Classification.ClassTypeList.ToList().Where(x => x.ClassType == MATERIALS_CLASS_NUMBER).First();
        }

        public static IList<ISAPDocument> ExtractDocumentsFromMaterial(DTP_MATERIAL_RMaterial sapMaterial) {
            IList<ISAPDocument> documentList = new List<ISAPDocument>();
            foreach (DTP_MATERIAL_RMaterialDocumentData document in sapMaterial.DocumentList) {
                documentList.Add(new SAPDocument() {
                    Description = document.Description,
                    DocType = document.Type,
                    Number = document.DocumentNumber,
                    Part = document.Part,
                    Version = document.Version
                });
            }
            return documentList;
        }
    }
}

