using System;
using System.Linq;
using Weg.Wdc.Ats.ProductManager.Core.Model;

namespace Weg.Wdc.Ats.ProductManager.Core.ModelImplementation {
    public class ProductLabel : IProductLabel {
        public long Order { get; set; }
        public long EanCode { get; set; }
        public long SerialNumber { get; set; }
        public long Batch { get; set; }
        public long Material { get; set; }

        public static IProductLabel generateFromBarcodeString(string barcode) {
            validateInput(barcode);
            return createLabel(barcode);
        }

        private static void validateInput(string barcode) {
            if (barcode == null || barcode.Length == 0) {
                throw new ArgumentNullException("The barcode can't be null or empty");
            }
        }

        private static IProductLabel createLabel(string barcode) {
            return new ProductLabel() {
                EanCode = ExtractData("01", barcode),
                SerialNumber = ExtractData("21", barcode),
                Order = ExtractData("91", barcode),
                Batch = ExtractData("10", barcode),
                Material = ExtractData("240",barcode)
            };
        }

        private static long ExtractData(string IdentifierCode, string barcode) {
            int idLen = IdentifierCode.Length;
            var v = barcode.Split(' ').Where(b => (b.Length >= idLen ? b.Substring(0, idLen) : b).Equals(IdentifierCode)).Select(b => b.Substring(IdentifierCode.Length)).SingleOrDefault();
            return (long.Parse(v == null || v == "" ? "0" : v));
        }

        public bool IsValid() {
            return Order != 0 || Material != 0 || SerialNumber != 0;
        }
    }
}

