using System;

namespace util {
    public partial class CodigoBarrasConverter {
        public DadosEtiqueta CodigoBarrasToDadosEtiqueta(string codigoBarras) {
            ValidarEntrada(codigoBarras);
            return new DadosEtiqueta(codigoBarras);
        }

        public string DadosEtiquetaToCodigoBarras(DadosEtiqueta dadosEtiqueta) {
            ValidarEntrada(dadosEtiqueta);
            return dadosEtiqueta.ToString();
        }
        private void ValidarEntrada(DadosEtiqueta Etiqueta) {
            if (Etiqueta == null) {
                throw new System.Exception("Nenhuma informação localizada na etiqueta");
            }
        }

        private void ValidarEntrada(string codigoBarras) {
            if (string.IsNullOrEmpty(codigoBarras)) {
                throw new System.Exception("Codigo de Barras está vazio");
            }
            if (codigoBarras.Split('\t').Length <= 1) {
                throw new System.Exception("Falta Informação no codigo de Barras");
            }
        }
    }

    public partial class DadosEtiqueta {
        public string Ordem { get; set; }
        public string Numero_Serie { get; set; }
        public string Lote { get; set; }
        public string EAN { get; set; }
        public string Material { get; set; }

        public DadosEtiqueta(string codigoBarras) {
            string[] dadosEtiquetaTemp = codigoBarras.Split('\t');

            foreach (string dado in codigoBarras.Split('\t')) {
                switch (dado.Substring(1, 2)) {
                    case "01":
                        EAN = dado.Substring(3);
                        break;

                    case "21":
                        Numero_Serie = dado.Substring(3);
                        break;

                    case "91":
                        Ordem = dado.Substring(3);
                        break;

                    case "10":
                        Lote = dado.Substring(3);
                        break;

                    default:
                        if (dado.Substring(1, 3)== "240") {
                            Material = dado.Substring(4);
                        }
                        break;

                }
            }
        }

        public override string ToString() {
            return string.Format("01{0} 21{1} 91{2} 10{3} 240{4}", EAN, Numero_Serie, Ordem, Lote, Material);
        }
    }
}

