using System;
using Weg.Wdc.Ats.F03.Daq.Entity;
using Weg.Wdc.Ats.F03.Daq.Model;
using Weg.Wdc.Ats.F03.Daq.ModelImplementation;
using Weg.Wdc.Ats.Equipment.Model;
using Weg.Wdc.Ats.ProductManager.Core.Types;
using Weg.Wdc.Ats.Core.F03.Model;
using Weg.Wdc.Ats.Core.F03.Types;
using System.Threading;
using Weg.Wdc.Ats.F03.Core.Properties;
using Weg.Wdc.Ats.F03.Core.ModelImplementation;
using Weg.Wdc.Ats.Equipment.ModelImplementation;
using System.Diagnostics;

namespace Weg.Wdc.Ats.Core.F03ModelImplementation {
    public class PositionControl : IPositionControl {

        private IMultimeter multimeter;
        private ISpeedMeter speedmeter;

        private IDAQAnalogInput daqAnalogInput;
        private IDAQAnalogOutput daqAnalogOutput;
        private IDAQDigitalOutput daqDigitalOutput;
        private IDAQDigitalInput daqDigitalInput;

        private DAQControlMappingIO daqControlMappingIO = new DAQControlMappingIO();

        /*public PositionControl() : this(new Multimeter(), new SpeedMeterPLC300()) {

        }*/
        public PositionControl(IMultimeter multimeter, ISpeedMeter speedmeter) {
            Debug.WriteLine("initializing PositionControl");
            initialize();
            this.multimeter = multimeter;
            this.speedmeter = speedmeter;
        }

        private void initialize() {

            daqAnalogInput = new DAQAnalogInput();
            daqAnalogOutput = new DAQAnalogOutput();
            daqDigitalOutput = new DAQDigitalOutput();
            daqDigitalInput = new DAQDigitalInput();
        }

        public bool IsBrakingActivated //Fazer com o contador, pegar do 11 ou 700. 
        {
            get {
                return daqDigitalInput.ReadFromDIChannel(daqControlMappingIO.brakingSignal);
            }
        }

        public int MotorSpeed {
            get {
                return speedmeter.Value;
            }
        }

        public double OutputCurrent {
            get {
                return ((multimeter.OutputCurrentRMS)/10);
            }
        }

        public double PositivePowerSupply_24V {
            get {
                return daqAnalogInput.ReadFromAnalogInputChannel(daqControlMappingIO.productAui24VccPowerSupply);
            }
        }

        public double PositivePowerSupply_10V {
            get {
                return daqAnalogInput.ReadFromAnalogInputChannel(daqControlMappingIO.productAui10VccPowerSupply);
            }
        }

        public double VoltageLinkCC {
            get {
                return Math.Round((multimeter.InputVoltageRMS) * Math.Sqrt(2),0);
            }
        }

        public void DisconnectMotor() {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.smallMotorIn220V, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.smallMotorIn440V, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.smallMotorIn760V, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.largeMotorIn220V, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.largeMotorIn440V, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.largeMotorIn760V, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.smallMotorEncoder, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.largeMotorEncoder, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.connectEncoderPowerSupply, false);
        }

        public void ExecuteGroundFaultSimulation() {
            SetGroundFaultSimulatorState(true); // ativa 
            Thread.Sleep(300);
            SetGroundFaultSimulatorState(false); // Desativa
        }

        public void Reset() {
            TurnOffMainPowerSupply();
            DisconnectMotor();
            SetDigitalInputState(1, false);
            SetDigitalInputState(2, false);
            SetDigitalInputState(3, false);
            SetDigitalInputState(4, false);
            SetDigitalInputState(5, false);
            SetDigitalInputState(6, false);
            SetAnalogInputValue(1, 0.0);
            SetAnalogInputValue(2, 0.0);
            TurnOffExternalControlPowerSupply();

        }

        public void SelectMotor(MotorType motorType) {
            switch (motorType) {
                case MotorType.Motor_1_220V:
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.smallMotorIn220V, true);
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.smallMotorEncoder, true);
                    break;
                case MotorType.Motor_1_440V:
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.smallMotorIn440V, true);
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.smallMotorEncoder, true);
                    break;
                case MotorType.Motor_1_760V:
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.smallMotorIn760V, true);
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.smallMotorEncoder, true);
                    break;
                case MotorType.Motor_2_220V:
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.largeMotorIn220V, true);
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.largeMotorEncoder, true);
                    break;
                case MotorType.Motor_2_440V:
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.largeMotorIn440V, true);
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.largeMotorEncoder, true);
                    break;
                case MotorType.Motor_2_760V:
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.largeMotorIn760V, true);
                    daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.largeMotorEncoder, true);
                    break;
            }
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.connectEncoderPowerSupply, true);
        }

        public void SelectMotor(MainPowerSupplyType nominalVoltage, int nominalCurrent) {
            switch (nominalVoltage) {
                case MainPowerSupplyType.Voltage_220V:
                    if (nominalCurrent <= 300) {
                        SelectMotor(MotorType.Motor_1_220V);
                    } else {
                        SelectMotor(MotorType.Motor_2_220V);
                    }
                    break;

                case MainPowerSupplyType.Voltage_440V:
                    if (nominalCurrent <= 250) {
                        SelectMotor(MotorType.Motor_1_440V);

                    } else {
                        SelectMotor(MotorType.Motor_2_440V);
                    }
                    break;

                case MainPowerSupplyType.Voltage_575V:
                case MainPowerSupplyType.Voltage_690V:
                    if (nominalCurrent <= 200) {
                        SelectMotor(MotorType.Motor_1_760V);
                    } else {
                        SelectMotor(MotorType.Motor_2_760V);
                    }
                    break;
            }
        }


        private void SetGroundFaultSimulatorState(bool active) {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.groundFaultSimulator, active);
        }

        private void SetShortCircuitSimulatorState(bool active) {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.shortCircuitFaultSimulator, active);
        }

        public void TurnOffMainPowerSupply() {
            TurnOffDCPreChargePowerSupply();
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.acPowerSupply, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.dcPowerSupply, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.inputVoltage220V, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.inputVoltage440V, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.inputVoltage575V, false);
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.inputVoltage690V, false);
            TurnOffPhaseLossSimulation();
            TurnOffPowerSupplyIndicator();
        }

        public void TurnOffPhaseLossSimulation() {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.phaseLossFaultSimulator, true);
        }

        public void TurnOnACPowerSupply() {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.acPowerSupply, true);
            SetPhaseLossState(false);
        }

        public void TurnOnExternalControlPowerSupply() {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.externalPowerSupply, true);
        }

        public void TurnOffExternalControlPowerSupply() {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.externalPowerSupply, false);
        }

        public void TurnOnDCPowerSupply() {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.dcPowerSupply, true);
        }

        public void TurnOnDCPreChargePowerSupply() {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.dcPowerSupplyPreCharge, true);
        }

        public void TurnOffDCPreChargePowerSupply() {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.dcPowerSupplyPreCharge, false);
        }

        public void TurnOnPowerSupplyIndicator() {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.mainPowerSupplyIndicator, true);
        }
        public void TurnOffPowerSupplyIndicator() {
            daqDigitalOutput.WriteToDOChannel(daqControlMappingIO.mainPowerSupplyIndicator, false);
        }
        public void TurnOnMainPowerSupply(int voltageCode) {
            if (isMainPowerSupplyOn()) {
                return;
            }

            TurnOffMainPowerSupply();

            switch (voltageCode) {
                case 2:
                    SelectMainPowerSupply(MainPowerSupplyType.Voltage_220V);
                    break;

                case 4:
                    SelectMainPowerSupply(MainPowerSupplyType.Voltage_440V);
                    break;

                case 5:
                    SelectMainPowerSupply(MainPowerSupplyType.Voltage_575V);
                    break;

                case 6:
                    SelectMainPowerSupply(MainPowerSupplyType.Voltage_690V);
                    break;

            }

            TurnOnACPowerSupply();
            TurnOnPowerSupplyIndicator();
        }

        private bool isMainPowerSupplyOn() {
            return IsVoltageSelected(MainPowerSupplyType.Voltage_220V) ||
                IsVoltageSelected(MainPowerSupplyType.Voltage_440V) ||
                IsVoltageSelected(MainPowerSupplyType.Voltage_575V) ||
                IsVoltageSelected(MainPowerSupplyType.Voltage_690V);
        }

        public void SelectMainPowerSupply(MainPowerSupplyType mainVoltage) {
            DigitalIO digitalIO = null;
            switch (mainVoltage) {
                case MainPowerSupplyType.Voltage_220V:
                    digitalIO = daqControlMappingIO.inputVoltage220V;
                    break;
                case MainPowerSupplyType.Voltage_440V:
                    digitalIO = daqControlMappingIO.inputVoltage440V;
                    break;
                case MainPowerSupplyType.Voltage_575V:
                    digitalIO = daqControlMappingIO.inputVoltage575V;
                    break;
                case MainPowerSupplyType.Voltage_690V:
                    digitalIO = daqControlMappingIO.inputVoltage690V;
                    break;
            }

